fn solve(weight: Vec<i64>) -> i64 {
    let n = weight.len();
    let mut max_count = 0;
    let mut i = 0;

    while i < n {
        let mut j = i;
        let mut max_weight = 0;
        while j < n {
            max_weight = std::cmp::max(max_weight, weight[j]);
            if weight[j] < max_weight {
                break;
            }
            j += 1;
        }

        if j > i + 1 {
            max_count += 1;
            i = j;
        } else {
            i += 1;
        }
    }

    max_count
}
